#include "XSbench_header.h"

////////////////////////////////////////////////////////////////////////////////////
// BASELINE FUNCTIONS
////////////////////////////////////////////////////////////////////////////////////
// All "baseline" code is at the top of this file. The baseline code is a simple
// implementation of the algorithm, with only minor CPU optimizations in place.
// Following these functions are a number of optimized variants,
// which each deploy a different combination of optimizations strategies. By
// default, XSBench will only run the baseline implementation. Optimized variants
// have not yet neen implemented in this OpenMP port.
////////////////////////////////////////////////////////////////////////////////////

unsigned long long run_event_based_simulation(Inputs in, SimulationData SD, int mype, double * sim_runtime)
{
	double start = get_time();

	// Allocate host memory for verification results
	int * verification_array_host = (int *) malloc( in.lookups * sizeof(int));
	if (verification_array_host == NULL) {
		fprintf(stderr, "Failed to allocate host memory for verification array.\n");
		exit(1);
	}

	// Variables for OpenMP
	unsigned long long verification = 0;
	double start_kernel = 0.0, end_kernel = 0.0;

	// Determine the number of threads to use
	int num_threads = in.nthreads;
	if (num_threads == 0) {
		#pragma omp parallel
		{
			#pragma omp master
			num_threads = omp_get_num_threads();
		}
	}
	omp_set_num_threads(num_threads);

	// Start the timer for the simulation kernel
	start_kernel = get_time();

	// Parallel region for the simulation
	#pragma omp parallel
	{
		// Each thread will have its own seed and local verification sum
		unsigned long long thread_verification = 0;
		uint64_t seed = STARTING_SEED; // Base seed

		// Forward seed to lookup index (we need 2 samples per lookup)
		// Each thread processes a subset of the lookups
		int thread_id = omp_get_thread_num();
		int total_threads = omp_get_num_threads();
		int lookups_per_thread = in.lookups / total_threads;
		int start_lookup = thread_id * lookups_per_thread;
		int end_lookup = (thread_id == total_threads - 1) ? in.lookups : start_lookup + lookups_per_thread;

		// Adjust seed for each thread and each lookup
		seed = fast_forward_LCG(seed, 2 * start_lookup);

		#pragma omp for schedule(static)
		for (int i = 0; i < in.lookups; i++) {
			// Randomly pick an energy and material for the particle
			double p_energy = LCG_random_double(&seed);
			int mat = pick_mat(&seed);

			double macro_xs_vector[5] = {0};

			// Perform macroscopic Cross Section Lookup
			calculate_macro_xs(
					p_energy,        // Sampled neutron energy (in lethargy)
					mat,             // Sampled material type index neutron is in
					in.n_isotopes,   // Total number of isotopes in simulation
					in.n_gridpoints, // Number of gridpoints per isotope in simulation
					SD.num_nucs,     // 1-D array with number of nuclides per material
					SD.concs,        // Flattened 2-D array with concentration of each nuclide in each material
					SD.unionized_energy_array, // 1-D Unionized energy array
					SD.index_grid,   // Flattened 2-D grid holding indices into nuclide grid for each unionized energy level
					SD.nuclide_grid, // Flattened 2-D grid holding energy levels and XS_data for all nuclides in simulation
					SD.mats,         // Flattened 2-D array with nuclide indices defining composition of each type of material
					macro_xs_vector, // 1-D array with result of the macroscopic cross section (5 different reaction channels)
					in.grid_type,    // Lookup type (nuclide, hash, or unionized)
					in.hash_bins,    // Number of hash bins used (if using hash lookup type)
					SD.max_num_nucs  // Maximum number of nuclides present in any material
					);

			// For verification, and to prevent the compiler from optimizing
			// all work out, we interrogate the returned macro_xs_vector array
			// to find its maximum value index, then increment the verification
			// value by that index.
			double max = -1.0;
			int max_idx = 0;
			for (int j = 0; j < 5; j++) {
				if (macro_xs_vector[j] > max) {
					max = macro_xs_vector[j];
					max_idx = j;
				}
			}
			// Store result in thread-local verification array
			verification_array_host[i] = max_idx + 1;
		}
	} // End of parallel region

	// End the timer for the simulation kernel
	end_kernel = get_time();
	*sim_runtime = end_kernel - start_kernel;

	// Reduce the verification results from all threads
	if (mype == 0) printf("Reducing verification value...\n");
	for (int i = 0; i < in.lookups; i++) {
		verification += verification_array_host[i];
	}

	// Free host memory
	free(verification_array_host);

	return verification;
}

// binary search for energy on nuclide energy grid
long grid_search_nuclide( long n, double quarry, NuclideGridPoint * A, long low, long high)
{
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint].energy > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

double LCG_random_double(uint64_t * seed)
{
	// LCG parameters
	const uint64_t m = 9223372036854775808ULL; // 2^63
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;
	*seed = (a * (*seed) + c) % m;
	return (double) (*seed) / (double) m;
}

